// For I/O-heavy server:
#[tokio::main(flavor = "multi_thread", worker_threads = 4)]
async fn main() { run_server().await }

// For simple tool:
#[tokio::main(flavor = "current_thread")]
async fn main() { run_tool().await }

// Custom runtime:
let rt = tokio::runtime::Builder::new_multi_thread()
    .worker_threads(4)
    .max_blocking_threads(32)
    .enable_all()
    .build()?;

use tokio::task::JoinSet;

async fn process_batch(items: Vec<Item>) -> Vec<Result<Output, Error>> {
    let mut set = JoinSet::new();
    for item in items {
        set.spawn(async move { process_item(item).await });
    }
    let mut results = Vec::new();
    while let Some(result) = set.join_next().await {
        match result {
            Ok(Ok(output)) => results.push(Ok(output)),
            Ok(Err(e)) => results.push(Err(e)),
            Err(join_err) => tracing::error!("task panicked: {join_err}"),
        }
    }
    results
}

