use tokio::time::{self, Duration, Instant};

// Non-blocking sleep:
time::sleep(Duration::from_secs(1)).await;

// Periodic task:
let mut interval = time::interval(Duration::from_secs(30));
loop {
    interval.tick().await;
    run_periodic_task().await;
}

// Timeout:
